INSERT INTO "canvas_concepts" VALUES(3,'реинкарнация','','ра Сингха Диллона, в которой последовательно рассматриваются темы, издавна присутствующие в религиозном сознании людей Южной Азии: смерть, жизнь после смерти, чаураси лакх (8,4 миллионов форм жизни), реинкарнация, рай и ад, мукти, дарга, Дхарм Радж, Яма Дуты, Читрагупт, питары (умершие предки) и другие. Особенность подхода, представленного в этой книге, состоит в том, что перечисленные понятия рассматриваются не как нечто впервые возникшее в Сикхи, а как уже существовавшие представления, получившие в учении Шри Гуру Грантх Сахиба глубокое и революционное переосмысление. Название «Холст Гуру Нанака» выражает основной образ, объединяющий всю книгу. Под «холстом» здесь понимается внутреннее поле человеческого сознания, уже наполненное устоявшимися представлениями, символами, страхами, ожидан','','canvas_ksd');
