INSERT INTO "canvas_concepts" VALUES(27,'дхарм радж','','ь 3. Жизнь После Смерти Часть 4. Чаураси Лакх — 8,4 Миллиона Форм Жизни Часть 5. Реинкарнация — Ава Гаун Часть 6. Рай и Ад Часть 7. Спасение — Мукти — Джеван Мукт Часть 8. Суд — Дарга Часть 9. Дхарм Радж Часть 10. Яма Дуты и Читра Гупт Часть 11. Предки — Питар Часть 12. Применение Холста Часть 1: Холст Гуру Нанака Часть 2: Смерть Часть 3: Жизнь После Смерти Часть 4: Чаураси Лакх — 8,4 Миллиона Форм Жизни Часть 5: Реинкарнация — Ава Гаун Часть 6: Рай и Ад Часть 7: Спасение — Мукти — Джеван Мукт Часть 8: Суд — Дарга Часть 9: Дхарм Радж Часть 10: Яма Дуты и Читра Гупт Часть 11: Предки — Питар Часть 12: Применение Холста Холст Гуру Нанака Карминдер Сингх Диллон | Концепции Сикхи | Часть 1 из 12 Источник: https://asiasamachar.com/2021/05/05/guru-nanaks-canvas/ Карминдер Сингх | Концеп','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(28,'яма дуты','','ти Часть 4. Чаураси Лакх — 8,4 Миллиона Форм Жизни Часть 5. Реинкарнация — Ава Гаун Часть 6. Рай и Ад Часть 7. Спасение — Мукти — Джеван Мукт Часть 8. Суд — Дарга Часть 9. Дхарм Радж Часть 10. Яма Дуты и Читра Гупт Часть 11. Предки — Питар Часть 12. Применение Холста Часть 1: Холст Гуру Нанака Часть 2: Смерть Часть 3: Жизнь После Смерти Часть 4: Чаураси Лакх — 8,4 Миллиона Форм Жизни Часть 5: Реинкарнация — Ава Гаун Часть 6: Рай и Ад Часть 7: Спасение — Мукти — Джеван Мукт Часть 8: Суд — Дарга Часть 9: Дхарм Радж Часть 10: Яма Дуты и Читра Гупт Часть 11: Предки — Питар Часть 12: Применение Холста Холст Гуру Нанака Карминдер Сингх Диллон | Концепции Сикхи | Часть 1 из 12 Источник: https://asiasamachar.com/2021/05/05/guru-nanaks-canvas/ Карминдер Сингх | Концепции Сикхи | Часть 1 из','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(29,'питар','','орм Жизни Часть 5. Реинкарнация — Ава Гаун Часть 6. Рай и Ад Часть 7. Спасение — Мукти — Джеван Мукт Часть 8. Суд — Дарга Часть 9. Дхарм Радж Часть 10. Яма Дуты и Читра Гупт Часть 11. Предки — Питар Часть 12. Применение Холста Часть 1: Холст Гуру Нанака Часть 2: Смерть Часть 3: Жизнь После Смерти Часть 4: Чаураси Лакх — 8,4 Миллиона Форм Жизни Часть 5: Реинкарнация — Ава Гаун Часть 6: Рай и Ад Часть 7: Спасение — Мукти — Джеван Мукт Часть 8: Суд — Дарга Часть 9: Дхарм Радж Часть 10: Яма Дуты и Читра Гупт Часть 11: Предки — Питар Часть 12: Применение Холста Холст Гуру Нанака Карминдер Сингх Диллон | Концепции Сикхи | Часть 1 из 12 Источник: https://asiasamachar.com/2021/05/05/guru-nanaks-canvas/ Карминдер Сингх | Концепции Сикхи | Часть 1 из 12 | Примечание для русскоязычного чита','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(30,'хукам','','anna. Смысл строфы таков: Принятый во Благоволение Сикх Гуру Нанака — тот, кто живёт в НАСТОЯЩЕМ. Что бы ни происходило в жизни — принятый Сикх с благодарностью склоняет голову перед Волей Создателя (Хукамом). Итак, это ПРОЖИВАНИЕ в НАСТОЯЩЕМ, жизнь ЗДЕСЬ и СЕЙЧАС — и есть уникальность Сикхи. Это её нирмалта — чистота. Делая это, Гуру Нанак полностью перевернул само основание духовности. Это потребовало совершенно иного мышления. Иного образа жизни. ТОГДА ПОЧЕМУ — можете вы спросить — ВСЕ концепции старого холста упоминаются в СГГС (Сири Гуру Грантх Сахиб)? ЕСЛИ старый холст действительно был отвергнут — зачем о нём вообще говорить? Дело в том, что холст — не физический. Физический холст можно уничтожить, смять и выбросить. Но мы говорим о ментальном холсте. А ментальный холст нельзя уничт','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(31,'наам','','an Dhan Nanak Prabh Maray Kirpa Keejaiy. Значение: Духовная смерть — через разлучение с Божественной осознанностью. Духовная жизнь — через обретение Божественных Добродетелей. Основа духовной жизни — Наам. СТИХ 9 (Кабир, СГГС, 330): ਗਉੜੀ ਕਬੀਰ ਜੀ ॥ ਕੈਸੇ ਜੀਵਨੁ ਹੋਇ ਹਮਾਰਾ ॥ ਜਬ ਨ ਹੋਇ ਰਾਮ ਨਾਮ ਅਧਾਰਾ ॥ ੧ ॥ ਰਹਾਉ ॥ Gaurri Kabeer Ji. Kaisay Jeevan Hoey Hmara. Jub Na Hoey Ram Naam Adhara. Значение: Как обрести Духовную Жизнь, если она не основана на Божественных Добродетелях? — спрашивает Кабир. Здесь ясно, что духовная жизнь обусловлена божественными добродетелями. А духовная смерть обусловлена отсутствием божественных добродетелей. СТИХ 10 (СГГС, 580): ਆਵਾ ਗਵਣੁ ਸਿਰਜਿਆ ਤੂ ਥਿਰੁ ਕਰਣੈਹਾਰੋ ॥ ਜੰਮਣੁ ਮਰਣਾ ਆਇ ਗਇਆ ਬਧਿਕੁ ਜੀਉ ਬਿਕਾਰੋ ॥ Ava Gaunn Sirjiya Tu Thir Karnaiharo. Jamann Marnna Aye Gya Badkhik Jio Bikar','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(32,'симран','','Гаун или Реинкарнация в Гурбани. Это качание между Камом, Кродхом, Лобхом, Мохом — ਕਾਮ ਕ੍ਰੋਧੁ ਲੋਭ ਮੋਹ — Kam Krodh Lobh Moh — похотью, гневом, жадностью, привязанностью — и Бхагати, Любовью к Творцу, Симраном — ਸਦਾ ਆਵਾ ਗਵਣ — Sda Ava Gavan — это и есть вечный Ава Гаун. И Гуру джи говорит в следующем стихе: этот цикл РЕИНКАРНАЦИИ ЗДЕСЬ и СЕЙЧАС можно устранить — ਮਿਟਤ ਜੋਨੀ ਭਵਣ — Mitet Joni Bhavann — через Бхакти, Любовь к Творцу и Симран. Гуру Нанак приводит этот стих на странице 1127 СГГС: ਭਰਮੁ ਭੇਦੁ ਭਉ ਕਬਹੁ ਨ ਛੂਟਸਿ ਆਵਤ ਜਾਤ ਨ ਜਾਨੀ ॥ ਬਿਨੁ ਹਰਿ ਨਾਮ ਕੋ ਮੁਕਤਿ ਨ ਪਾਵਸਿ ਡੂਬਿ ਮੁਏ ਬਿਨੁ ਪਾਨੀ॥ Bhrm Bheyd Bho Kbeh Na Chutes Aavat Jaat Na Jani. Bin Har Naam Ko Mukt Na Pavas Doob Muey Bin Paani. Три слова — ਭਰਮੁ ਭੇਦੁ ਭਉ — Bhrm Bheyd Bho — означают иллюзию, заблуждение и страх. Все они — негативные умственны','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(33,'гурбани','','бым меркам — колоссальный. Он целостный и завершённый. Любая концепция, которая может понадобиться для духовной жизни, — переопределена внутри его страниц. Поэтому вопрос прост. Когда мы хотим понять Гурбани, истолковать её или перевести, обращаемся ли мы к 4000-летнему словарю отвергнутого холста? Или к словарю, определённому самой Гурбани — в пределах 1429 страниц СГГС? Возможно, это звучит как риторический вопрос. Но причина, по которой его нужно задать, проста. Практически все наши переводы Гурбани прибегают к словарю отвергнутого 4000-летнего холста. Результат: в целом сикхи вернули Сикхи к старому холсту. ПОЧЕМУ МЫ ЖИВЁМ НА ОТВЕРГНУТОМ ХОЛСТЕ? И вопрос таков: ПОЧЕМУ сикхи живут на отвергнутом холсте? Почему сикхи живут по старому холсту и принимают старые концепции как суть своей дух','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(34,'кал','','рх уже расписанного холста. Духовный портрет Гуру Нанака был сосредоточен на Жизни Здесь и Сейчас. Он был написан поверх почти 4000-летнего холста, одержимого жизнью после смерти. В этом и состоит уникальность портрета Гуру Нанака. Этот первичный принцип Гуру Нанак утверждает на странице 20 Шри Гуру Грантх Сахиба (СГГС). ਸਿਰੀਰਾਗੁ ਮਹਲਾ ੧ ॥ ਸੁਣਿ ਮਨ ਮਿਤ੍ਰ ਪਿਆਰਿਆ ਮਿਲੁ ਵੇਲਾ ਹੈ ਇਹ ॥ ਜਬ ਲਗੁ ਜੋਬਨਿ ਸਾਸੁ ਹੈ ਤਬ ਲਗੁ ਇਹੁ ਤਨੁ ਦੇਹ ॥ Sri Rag Mehla 1. Sunn Mun Miter Pyariya Mil Veyla Hai Eh. Jub Lug Joban Saas Hai Tub Lug Eh Tun Deh. (SGGS, 20) Смысл этой строфы таков: О возлюбленный Ум, слушай! Время осознать Творца — это Здесь и Сейчас. Божественность присутствует в этом теле, пока в нём есть дыхание юности. Духовность Гуру Нанака — для ЗДЕСЬ и СЕЙЧАС. Бхаи Гурдас Джи выражает это следующим образом. ਨਾਨਕ','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(35,'джам','','ти нашей совести. О предотвращении смерти нашей духовности. Речь идёт о том, чтобы не стать ходячими мертвецами. О том, чтобы не превратиться в существ с мёртвыми душами. Вот цитата, приписываемая Бенджамину Франклину. Она ясно показывает, что он очень хорошо понимал концепцию смерти совести: Многие люди умирают в 25 лет, но их хоронят только в 75. Почему именно в 25, спросите вы? 25 – это расцвет молодости. Смысл здесь в том, что смерть совести происходит, когда люди вступают в расцвет молодости – в 25 лет или около того. Как и почему это происходит? Гурбани даёт ответы. Духовная жизнь основана на добродетелях. В основе всего лежит понимание божественных добродетелей, их принятие, привитие божественных добродетелей, их усвоение и, наконец, становление божественными добродетелями. В конечн','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(36,'нарак','','и применять к ним смысл старого холста. Нужно искать новый, гурбани-смысл. В сегодняшнем выпуске рассматриваются концепции Рая и Ада. Панджабские термины для Рая — Сурадж, Бхист и Байкунтх. Для Ада — Нарак и Доджак. Начнём с того, как Рай и Ад описаны на четырёхтысячелетнем старом холсте. Главное утверждение: после суда Дхарм Раджа душа усопшего отправляется либо в Рай, либо в один из 21 вида Ада. Более 100 миллиардов людей жили и умирали до нас. Ни один не вернулся рассказать о Рае или Аде. Тем не менее сфабрикованные детали обоих мест преподносятся как религиозный факт. Пугающие подробности этих двух мест преподносятся как религиозный ФАКТ и религиозная ИСТИНА. Самое леденящее — то, что именно этот нарратив о Рае и Аде из четырёхтысячелетнего старого холста продолжает звучать на большинс','','canvas_combined_ru');
INSERT INTO "canvas_concepts" VALUES(37,'смерть','','и (Шри Гуру Грантх Сахиб). В её основу положена серия лекций Карминдера Сингха Диллона, в которой последовательно рассматриваются темы, издавна присутствующие в религиозном сознании людей Южной Азии: смерть, жизнь после смерти, чаураси лакх (8,4 миллионов форм жизни), реинкарнация, рай и ад, мукти, дарга, Дхарм Радж, Яма Дуты, Читрагупт, питары (умершие предки) и другие. Особенность подхода, представленного в этой книге, состоит в том, что перечисленные понятия рассматриваются не как нечто впервые возникшее в Сикхи, а как уже существовавшие представления, получившие в учении Шри Гуру Грантх Сахиба глубокое и революционное переосмысление. Название «Холст Гуру Нанака» выражает основной образ, объединяющий всю книгу. Под «холстом» здесь понимается внутреннее поле человеческого сознания, уже','','concepts_sikhi');
