INSERT INTO "words" VALUES(522,'','такое восприятие','тоже логично, ведь в предыдущих паури мы говорим о "становлении" божественностью. И Асанкх паури - это то, что происходит в результате такого становления.','',NULL,'jbani_v2',0.85,NULL);
