INSERT INTO "words" VALUES(532,'','со','Весть - это знание, приходящее "бесконтрольно", от Творца, связанное с необходимостью реализовывать это знание, эту Весть Творца.','',NULL,'jbani_v2',0.85,NULL);
INSERT INTO "words" VALUES(533,'','команда творца, возникает из просветленной совести','потому что это говорит Творец. Совесть пришла к тому, чтобы принять Творца, пребывающего внутри. Как только эта реальность принята, тогда голос совести становится голосом Творца.','',NULL,'jbani_v2',0.85,NULL);
