INSERT INTO "words" VALUES(632,'','простой акт поднятия насекомого, кормления кошки','гораздо более благой акт. Поднятие насекомого от опасности - великое благо. Ищем мирских наград или духовных? Количество, качество, размер, видимость - это то, что важно во внешнем мире. Поэтому я продал весь дом, чтобы получить это всё.','',NULL,'jbani_v2',0.85,NULL);
