INSERT INTO "words" VALUES(883,'','этот паури появляется трижды в сггс, отчего','он крайне важен. В Джап бани, в Содар, в Аса Рааг Бани. Иногда он появляется в несколько измененной поэтической форме - в зависимости от поэтической структуры шабда, в которую он втекает.','',NULL,'jbani_v2',0.85,NULL);
