INSERT INTO "words" VALUES(1333,'','бани','это духовный совет к реализации, а не к повторению','“мантра” находится внутри Шабда, находится в послании, которое должно быть усвоено и реализовано.',NULL,'jbani_v1',0.85,NULL);
