INSERT INTO "words" VALUES(1336,'','jup / jaap','знать, понимать. Под “джап” имеется в виду то, что можно было бы назвать “повторяй за мной (пройди тот же путь)”, или “воспроизведи это (в жизни)”','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1337,'','в гурбани, муул','это Бог, творец.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1338,'','куда бы я ни посмотрел','там я нахожу корни Творца (mool)/ Творец повсеместно (т.е. Творец есть Корень всего и присутствует во всем и в каждом)','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1339,'','название задаёт определение использованию','предназначено для познания, предназначено как основа, предназначено как “якорь” божественных добродетелей в сознании Сикхов.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(1340,'','здесь важен мыслительный процесс','Бог определяется добродетелями (Наам).','',NULL,'jbani_v1',0.85,NULL);
