INSERT INTO "words" VALUES(1431,'','то есть, кто','то ощущает Хукам - как силу нашего существования. Мы существуем потому, что в нас есть некая сила, которая движет нами. Когда она перестаёт двигать нами, эта сила принимает решения об этом. Существованию приходит конец.','',NULL,'jbani_v1',0.85,NULL);
