INSERT INTO "words" VALUES(1479,'','sacha','значит, неизменный, за пределами влияния причин и следствий. Как узнали? Через мудрость погружения в знание Хукама. Вода - существует в трёх формах, вода, лёд, пар. Это Хукам. Хукам - постоянен в этом плане.','',NULL,'jbani_v1',0.85,NULL);
