INSERT INTO "words" VALUES(1832,'','такое восприятие','тоже логично, ведь в предыдущих паури мы говорим о "становлении" божественностью. И Асанкх паури - это то, что происходит в результате такого становления.','',NULL,'jbani_v1',0.85,NULL);
