INSERT INTO "words" VALUES(1835,'','тот, в чьей жизни все, что имеет значение','это воля и команда Творца (Jo Vartaye Saee Jugat) это существо, Нанак описывает как Дживан Мукат (ਜੀਵਨ ਮੁਕਤਿ)  - кто достиг Мукти - Здесь и Сейчас.','',NULL,'jbani_v1',0.85,NULL);
