INSERT INTO "words" VALUES(1837,'','а творец','безграничен. Его дискурс, Вичар, разговор о его мудрости - это безграничная Реальность, выражающая этот дискурс. Поэтому, не может быть полного рассуждения об этой совести.','',NULL,'jbani_v1',0.85,NULL);
