INSERT INTO "words" VALUES(1973,'','внутри меня','темно или светло. Неважно, кто там в мире - тёмен или светел. Всё - для меня. Почему Гуру рассказывает нам о других людях и о том, что происходит снаружи? Как нам помогает знание о том, когда создана Земля? Это не прибавляет Sat Sohan Sda Man Chao.','',NULL,'jbani_v1',0.85,NULL);
