INSERT INTO "words" VALUES(2358,'','sansari','это не Создатель. Sansar - это мир. Sansari относится к миру, мирскому (wordly). Bhandari это не “поддерживатель / сохранитель”, а владелец того или иного хранилища. Laye Diban - относится к “суду”, “сидеть в суде”, а не к разрушению.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2359,'','даже если это относится к критике этого паури','это всё так же вне контекста. Откуда бы критика “трёх божеств” пришла в этот паури, какие предпосылки говорить об этом?','',NULL,'jbani_v1',0.85,NULL);
