INSERT INTO "words" VALUES(2604,'','карми','не о карме. Не о прошлой жизни. Нанак ясно нам говорит, что мы создаём свою судьбу своими выборами основываясь на понимании последствии наших поступках.','',NULL,'jbani_v1',0.85,NULL);
