INSERT INTO "words" VALUES(2611,'','dhiayia','созерцать что-то, чтобы стать созерцаемым','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2612,'','gye','(Lit) шёл, проезжал, путешествовал','становиться',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2613,'','masakat','(по арабски) трудный процесс, напряженный, требующий трудной работы','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2614,'','ghaal','санскристская версия для Mushakat','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2615,'','нанак хочет прояснить кое','что в своей жизни. Духовность Нанака - не “прогулка по парку”, это работа над мышлением и над своими поступками.','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2616,'','tay','они, те','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2617,'','mukh ujlay','(Lit) светлолицый, по типу “солнцеликий”','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2618,'','kayti','недомогание, болезнь, недуг, заболевание, хворь, расстройство','как Koor, Koorearr',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2619,'','chutti','освобождение, преодоление недомогания','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2620,'','naal','с, посредством (чего-то)','',NULL,'jbani_v1',0.85,NULL);
INSERT INTO "words" VALUES(2621,'','это','повествование о портрете Сикхи. Точнее, это история холста, на котором портрет Сикхи обретает жизнь.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2622,'','холст','а им был человеческий УМ — уже был расписан тысячей образов.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2623,'','гуру нанак обнаружил, что человеческий ум','духовный холст людей его времени — был расписан образами рая и ада, 8,4 миллиона форм жизни после смерти, слуг смерти, ангелов смерти и круговорота рождений и смертей (Ava Gaun), перевоплощений.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2624,'','но было ещё кое','что. Существующий холст был сосредоточен на Смерти. Это был холст, одержимый жизнью после смерти и зацикленный на загробном мире.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2625,'','духовность гуру нанака','для ЗДЕСЬ и СЕЙЧАС.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2626,'','духовность гуру нанака была нирмал','чистой. Она была уникальной. Нирмал — потому что в ней не было загрязнений отринутого холста: ни “небес”, ни ада, ни 8,4 миллиона форм жизни, ни перевоплощений, ни судей, ни вестников смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2627,'','и прежде всего','нирмал потому, что она предлагала духовность для жизни в настоящем, а не для какого-то неизвестного и непознаваемого БУДУЩЕГО — будущего, которое никто никогда не видел и не переживал.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2628,'','тогда почему','можете вы спросить — ВСЕ концепции старого холста упоминаются в СГГС (Сири Гуру Грантх Сахиб)? ЕСЛИ старый холст действительно был отвергнут — зачем о нём вообще говорить?','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2629,'','дело в том, что холст','не физический. Физический холст можно уничтожить, смять и выбросить. Но мы говорим о ментальном холсте. А ментальный холст нельзя уничтожить, сжечь или забросить.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2630,'','подавляющее большинство нас, сикхов,','сикхи лишь внешне. Уникальны по облику. Но наш ОБРАЗ МЫШЛЕНИЯ сформирован 4000-летним старым холстом.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2631,'','способ, которым гуру нанак писал поверх него,','новаторский, изобретательный и удивительный. Это способ, которым пользуются, когда хотят перекрасить внутренние стены помещения.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2632,'','переопределение','вот путь. Правильный и верный путь. Единственный способ дать людям НОВОЕ МЫШЛЕНИЕ. Гуру Нанак переопределил всё это внутри страниц СГГС.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2633,'','если ответ хотя бы на один из этих вопросов','да, то нам следует знать: это — столпы отвергнутого холста, а не холста Гуру Нанака.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2634,'','духовность ритуалов','со старого холста. На холсте Гуру Нанака она заменяется духовностью Просветления.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2635,'','в этих классических текстах','по сути, выдумки, замаскированные под сакхи, в которых наши Гуру действуют и живут согласно концепциям старого, отвергнутого холста.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2636,'','подобное разложение','осуществляемое, потворствуемое, принимаемое и проповедуемое на протяжении длительного времени — производит следующий эффект. Истинный Холст Гуру Нанака оказывается подменён старым, отвергнутым холстом.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2637,'','наше духовенство','грантхи, раги, катхакары, проповедники и писатели — не просто держится за старый холст, но и проповедует его как подлинную Сикхи.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2638,'','и это','потому что мы проигнорировали тот факт, что все существующие концепции отвергнутого холста были ПЕРЕОПРЕДЕЛЕНЫ. Мы игнорируем переопределённые значения.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2639,'','sikhi concepts','Часть 2 из 12: СМЕРТЬ','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2640,'','во','первых — потряс само основание старого холста, разрушил два его столпа: смерть и страх перед тем, что после.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2641,'','первое, что делает гурбани','ещё ДО переопределения смерти — это даёт правильное, сбалансированное и реалистичное понимание физической смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2642,'','это выравнивание освобождает','ибо избавляет от страха перед выдуманным странствием и беспокойства о ложном суде.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2643,'','это выравнивание осмысленно','ибо говорит: живи в полную силу, здесь и сейчас, вплоть до момента неизбежной физической смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2644,'','ava gavan означает','цикл жизни и смерти. В контексте Gurbani это цикл духовной жизни и духовной смерти. Помните о переопределении. Именно переопределённые значения приведут нас к тем смыслам, которые Gurbani намеревается передать.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2645,'','фраза aye gya','приход и уход — относится к духовной жизни, духовной смерти и к циклу духовной жизни и духовной смерти соответственно, потому что следующая часть шлока содержит выражение Badhik Jio Bikaro.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2646,'','смерть, которая наступает из','за связанности пороками, — это духовная смерть.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2647,'','цикл, который возникает из','за связанности пороками, — это цикл ДУХОВНОЙ жизни и ДУХОВНОЙ смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2648,'','слова marta / marna / mar и mua','все означают смерть. В этом одном-единственном двустишии содержится 7 упоминаний смерти. Но из этих семи только одно употреблено в значении физической смерти. В остальных 6 случаях речь идёт о духовной смерти и смерти по причине пороков.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2649,'','в','третьих, Гурбани определяет физическую смерть как возвращение к нашим истокам.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2650,'','фокус гуру нанака','на предотвращении духовной смерти, а его устремление — на том, чтобы избежать смерти нашей совести.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2651,'','и если мы хотим по','настоящему понять Сикхи Гуру Нанака, нам нужно понять НОВЫЕ значения — ПЕРЕОПРЕДЕЛЁННЫЕ смыслы — этих концепций.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2652,'','первое','Познаваемость. Утверждается, что природа и характер жизни после смерти полностью известны. Что она хорошо изучена. Что о ней можно рассуждать с абсолютной уверенностью и авторитетностью.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2653,'','второе','путь описан с высокой степенью конкретности. Нарратив таков: душа отправляется в невероятное путешествие. Путешествие, у которого есть чёткие маршруты, вехи и пункты назначения.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2654,'','третье','определены этапы посмертного пути. Четырёхтысячелетний холст содержит детали вплоть до количества дней на каждом его отрезке.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2655,'','четвёртое','душа усопшего предстаёт перед Судом. Согласно нарративу, душе требуется один год, то есть 365 дней — один Барас — чтобы добраться до места Суда.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2656,'','пятое','душе усопшего назначается один из трёх путей: (1) на небеса, (2) в один из 21 вида ада, или (3) снова в жизнь — в форме одного из 8,4 миллиона видов живых существ.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2657,'','шестое','последние обряды: похороны, кремация или погребение — играют ключевую роль, поскольку именно они готовят душу к этому путешествию.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2658,'','и наконец','весь этот цикл повторяется.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2659,'','всё это','о путешествии, которое НИКТО не совершал, и о месте назначения, откуда никто не вернулся, чтобы поведать об увиденном.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2660,'','самое же леденящее','это то, что именно этот нарратив о загробной жизни, взятый с четырёхтысячелетнего холста, продолжает звучать на большинстве сикхских религиозных церемоний.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2661,'','подавляющее большинство сикхов справляют барси','годовщины смерти — хотя сама концепция барси основана именно на четырёхтысячелетнем холсте.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2662,'','первое, что делает гурбани,','это подвергает Критике саму концепцию Познаваемости, выдвинутую четырёхтысячелетним холстом.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2663,'','метафора','это поле. Последняя фаза поля — жатва. Отсюда термин ਲਾਵੀ ਆਇਆ ਖੇਤੁ — Lavee Aya Kheyt — «жатва пришла на поле».','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2664,'','если бы он одобрял этот нарратив','критики не было бы. Но она есть. И она содержится в том же стихе.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2665,'','вот ещё один стих гуру нанака','на странице 648 СГГС.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2666,'','воздух','к воздуху. Вода — к воде. Прах — к праху.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2667,'','что касается самой жизни','она тоже возвращается к своему Источнику — к Творцу. ਜੋਤੀ ਮਹਿ ਜੋਤਿ ਰਲਿ ਜਾਇਆ — Jyoti Meh Jyot Rul Jaya. Свет сливается со Светом (джот). Джот возвращается в Джот.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2668,'','если бы существовали какие','либо исключения, условия, процессы, ограничения — мы вправе спросить: каковы они? Где в Гурбани они описаны? Можно ли указать стих, параграф, страницу?','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2669,'','вот он','Цикл Жизни. Приходит по Хукаму. Уходит по Хукаму. ਹੁਕਮੇ ਆਵੈ ਹੁਕਮੇ ਜਾਵੈ ਹੁਕਮੇ ਰਹੈ ਸਮਾਈ — Hukmaiy Aveiy Hukmaiy Javeiy Hukmaiy Rhaiy Smayee.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2670,'','хукам','это ЦИКЛ. ਇਹੁ ਤਉ ਚਲਤੁ ਭਇਆ — Eh Tao Chalat Bhya. Это и есть Цикл: всё, что пришло из Источника — неизбежно возвращается к Источнику. Неисключений нет. Пути в обход нет. Это Хукм Творца.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2671,'','бхагат кабир выражает это следующим образом','на странице 1103 СГГС.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2672,'','суть в том, что я слился со своим творцом','внутри — ЗДЕСЬ и СЕЙЧАС. ਸੁੰਨਹਿ ਸੁੰਨੁ ਮਿਲਿਆ ਸਮਦਰਸੀ — Sunney Sunn Miliya Samdarsi. Равно видящий — тот, кто достиг слияния с Запредельным.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2673,'','она позволяет нам жить нашу жизнь','ЗДЕСЬ и СЕЙЧАС — в полную силу. Жить добродетельно. Жить так, чтобы стать Достойными — Гурмукхами. Жить так, чтобы обрести освобождение — Мукти — прямо здесь, в этой жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2674,'','когда нечто происходит снова и снова','тогда, по определению, оно может обесцениться. Но уж точно не быть бесценным. Именно поэтому бесценно то, что бывает лишь однажды.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2675,'','но человеческая жизнь','только РАЗ. Потому она и бесценна.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2676,'','чаураси лакх','8,4 Миллиона Форм Жизни','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2677,'','пугающие подробности этого путешествия','которое никто никогда не совершал — содержатся в многочисленных концептуальных текстах старого холста.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2678,'','иллюстративен следующий стих из гурбани','на странице 237 СГГС:','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2679,'','используемое слово','ਅਨਿਕ — Anuk — означает «бесчисленные, неисчислимые, бесконечные». ਅਨਿਕ ਜੋਨਿ — Anuk Joan — означает бесчисленные формы жизни. Не 8,4 миллиона. Бесчисленные.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2680,'','второй стих содержит упоминание ряда животных','ਕੂਕਰਹ ਸੂਕਰਹ ਗਰਧਭਹ ਕਾਕਹ — Kookreh Sookreh Gardhbey Kakeh — и ਸਰਪਨਹ — Sarpney: собака, свинья, осёл, ворона, змея. Все они — животные формы жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2681,'','если же взглянуть на первый стих','там мы видим ПЕРЕОПРЕДЕЛЕНИЕ в самом ясном виде.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2682,'','ключевые слова здесь','ਜੋ ਪ੍ਰਾਣੀ — Jo Pranni — «тот человек». Определённый тип человека. Живой человек — ਪ੍ਰਾਣੀ — Pranni — прямо сейчас, здесь.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2683,'','упоминание животных','ਸੂਕਰ ਸੁਆਨ ਗਰਧਭ ਮੰਜਾਰਾ — Sookar Suan Gardhab Manjara — служит отсылкой к УМСТВЕННЫМ СОСТОЯНИЯМ ЧЕЛОВЕКА. Свинья символизирует жадность. Осёл — упрямство. Собака — раболепие и услужливость. Кошка — лесть.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2684,'','вот ещё один стих','на странице 1418 СГГС:','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2685,'','те люди, которые не познали творца внутри себя','ਸਤਿਗੁਰੁ ਪੁਰਖੁ ਨ ਸੇਵਿਓ — Satgur Purakh Na Sayveyo — и не размышляли над Шабдом — ਸਬਦਿ ਨ ਕੀਤੋ ਵੀਚਾਰੁ — Shabd Na Keeto Vichar — таких Гуру называет не живущими в человеческой форме жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2686,'','следующая часть','ਪਸੂ ਹਉ ਕਰਿ ਜਾਣੀ — Psu Haon Kar Janni — означает: я низвёл свою жизнь — свою человеческую жизнь — ਕਰਿ ਜਾਣੀ — Kar Janni — до уровня животного.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2687,'','первый стих','ਮੇਰੇ ਸਾਹਿਬਾ ਕਉਣੁ ਜਾਣੈ ਗੁਣ ਤੇਰੇ — Mayray Sahiba Kaonn Janney Gun Tayray — о Божественных Добродетелях Творца. Никто не способен их постичь. Точно так же, ਕਹੇ ਨ ਜਾਨੀ ਅਉਗਣ ਮੇਰੇ — Khay Na Janni Augunn Mayray — мои пороки тоже невыразимы.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2688,'','все эти примеры','формы жизни: ਰੁਖ ਬਿਰਖ, ਪਸੂ, ਨਾਗ, ਪੰਖ — Rukh Birekh, Psu, Naag, Pankh — деревья, растительность, животные, змеи, птицы. И все они — ਕੇਤੇ — Kaytay — бесчисленны.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2689,'','вот ещё один набор стихов','на странице 802 СГГС:','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2690,'','очевидно, что смерть здесь','это ДУХОВНАЯ СМЕРТЬ — ਮਿਰਤਕ ਦੇਹ — Mirtak Deh — которая и составляет заботу Гурбани. И ФОРМЫ ЖИЗНИ — ਆਵਤ ਜਾਤ ਜੋਨੀ — Avat Jaat Joni — это СОСТОЯНИЯ РАЗУМА, в которых мы блуждаем здесь, в этой жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2691,'','по существу, то, что происходит в гурбани,','это ПЕРЕОПРЕДЕЛЕНИЕ концепции 8,4 миллиона форм жизни: из физического измерения (после смерти) — в духовное (здесь и сейчас). Это переход от внешнего к внутреннему. От посмертного — к ныне живому.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2692,'','то, что говорят все приведённые выше стихи,','что внутри нас есть Зоопарк. Зоопарк умственных состояний: состояние собаки, состояние свиньи, состояние осла, состояние вороны, состояние змеи, состояние дерева, состояние камня, состояние демона — и состояние человека, состояние просветлённого.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2693,'','гюго также сказал кое','что ещё. Он сказал: «Нет ничего сильнее идеи, время которой пришло». Гуру Нанак предложил нам духовность, время которой давно пришло. Ещё в 1469 году.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2694,'','мы можем изменить это в нашей жизни','признав, что время Сикхи Гуру Нанака пришло. Мы можем изменить — даже если наше духовенство не хочет или не способно.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2695,'','реинкарнация','Ава Гаун','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2696,'','самое леденящее','то, что именно этот нарратив о Реинкарнации из четырёхтысячелетнего старого холста продолжает звучать на большинстве сикхских религиозных церемоний.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2697,'','когда всё многообразие видов было создано впервые','до которого не было никаких видов, ਜਬ ਕਛੁ ਨ ਸੀਓ — Jub Kach Na Sio — какие тогда деяния совершила только что созданная душа? Никаких. Ни единого. Ни плохих, ни хороших.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2698,'','раз не было никаких деяний','что именно записывал так называемый Читр Гупт? Какие деяния он докладывал Дхарм Раджу на суде первых душ? Ответ: никакие. Потому что ни первых деяний, ни первого суда не было.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2699,'','если сикх гурбани думает самостоятельно','одного этого двустишия достаточно, чтобы разрушить весь сфабрикованный нарратив о Читр Гупте, Дхарм Радже и суде над деяниями.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2700,'','второе, что делает гурбани,','это ясно говорит: жизнь, которую мы имеем ЗДЕСЬ и СЕЙЧАС, является Единственной и Неповторимой жизнью.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2701,'','что это означает','«прийти снова»? ਬਹੁਰਿ ਹਮ ਕਾਹੇ ਆਵਹਿਗੇ — Bahur Hum Kahe(n) Aveh(n)gay. ਬਹੁਰਿ — Bahur — означает «снова, во второй раз». Кабир задаёт прямой вопрос: что такое «прийти обратно»? Каковы основания для самой концепции возвращения?','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2702,'','приход и уход','в Его Хукму — ਆਵਨ ਜਾਨਾ ਹੁਕਮੁ ਤਿਸੈ ਕਾ — Aavan Jaana Hukm Tisaiy Ka — и познав Хукм — ਹੁਕਮੈ ਬੁਝਿ — Hukmeiy Bujh — мы сливаемся — ਸਮਾਵਹਿਗੇ — Smaveh(n)gay.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2703,'','слияние','это антитеза возвращения. Слияние — это противоположность Реинкарнации. Когда сливаешься — ਹੁਕਮੈ ਬੁਝਿ ਸਮਾਵਹਿਗੇ — не возвращаешься. Потому что слияние — это именно слияние.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2704,'','если смерть переопределяется','то ЗАГРОБНАЯ ЖИЗНЬ и то, что ПОСЛЕ Смерти, тоже переопределяется как то, что происходит ПОСЛЕ духовной смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2705,'','цель','вырваться из этого цикла и пребывать постоянно в Духовной Жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2706,'','задача','стать Аджуни — то есть выйти за пределы цикла духовной жизни и духовной смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2707,'','это гурбани','ОПРЕДЕЛЕНИЕ Ава Гаун, РЕИНКАРНАЦИИ ясно из этих стихов на странице 971 СГГС:','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2708,'','реинкарнация или ава гаун гурбани','в этом шабаде — это цикл, происходящий ВНУТРИ меня. Внутри моего разума. В этой жизни. ЗДЕСЬ и СЕЙЧАС.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2709,'','итак, ава гаун, или цикл','это цикл, качающийся между состояниями Божественных Добродетелей и Человеческих Пороков. Это колебание происходит внутри нас — ЗДЕСЬ и СЕЙЧАС, в этой жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2710,'','переопределённая реинкарнация гурбани','это процесс, в котором я снова и снова рождаюсь — ਫੁਨਿ ਫੁਨਿ — Fun Fun — в состояниях пороков. И снова и снова — умираю духовно.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2711,'','ава гаун гурбани','это Цикл, качающийся как маятник между Духовной Жизнью — на основе Добродетелей — и Духовной Смертью — на основе Пороков. Цикл происходит ЗДЕСЬ и СЕЙЧАС. В нас. В этой жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2712,'','три слова','ਭਰਮੁ ਭੇਦੁ ਭਉ — Bhrm Bheyd Bho — означают иллюзию, заблуждение и страх. Все они — негативные умственные состояния, из-за которых мы блуждаем в Ава Гаун — ਆਵਤ ਜਾਤ ਨ ਜਾਨੀ — Aavat Jaat Na Jani.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2713,'','итак, цикл','это было колебание между просветлением и иллюзией. Конец цикла выражен словами ਕਾਟੀ ਬੇਰੀ ਪਗਹ ਤੇ ਗੁਰਿ ਕੀਨੀ ਬੰਦਿ ਖਲਾਸੁ — Katee Bayri Pgeh Teh Gur Kini Band Khlas — Гуру разрезал оковы на ногах — тюрьма разрушена, узник освобождён.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2714,'','и причина этого','в БАЗОВОМ и ФУНДАМЕНТАЛЬНОМ принципе Холста Сикхи Гуру Нанака.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2715,'','поэтому причина переопределения','в том, чтобы укоренить понятие 8,4 миллиона, понятие Джун, понятие Реинкарнации и Ава Гаун — в ЗДЕСЬ и СЕЙЧАС. Чтобы духовность работала для нас именно здесь и сейчас.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2716,'','когда ты перестаёшь жить духовностью второй жизни','ты начинаешь жить Единственной и Неповторимой Жизнью в Полную Силу.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2717,'','в следующем выпуске','части 6 из 12 — будут рассмотрены концепции Рая и Ада. Будет предложено новое, переопределённое Гурбани значение этих концепций.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2718,'','если сикх думает самостоятельно','одного этого двустишия достаточно, чтобы разрушить весь сфабрикованный нарратив о Рае и Аде.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2719,'','гуру арджун джи предлагает ещё одну критику','объясняющую, зачем вообще понадобилась эта выдумка. Стих на странице 295 СГГС:','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2720,'','чтобы этот нарратив работал','то есть чтобы заставить людей совершать одобренные духовенством деяния и избегать запрещённых — нужны были морковь и кнут. Рай — морковь. Ад — кнут.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2721,'','нарратив','ਕਥਾ ਕਹਾਣੀ — Ktha Kahanni — данный миру Ведами — ਬੇਦੀਂ ਆਣੀ — Beydi Aanni — таков: есть благочестивые деяния и греховные. Давай — получишь. Возьмёшь — отдашь. Результат: Рай или Ад. Таков нарратив.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2722,'','веды провозглашают','ਬੇਦੁ ਪੁਕਾਰੇ — Beyd Pukarey — что благочестивые и греховные деяния — ਪੁੰਨੁ ਪਾਪੁ — Punn Paap — являются определяющими критериями для Рая и Ада. Что посеешь — то и пожнёшь. Но Гуру Нанак здесь критикует этот нарратив, а не принимает его.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2723,'','все','ਸਭੁ ਕੋਈ — Sabh Koyi — утверждают, что знают, как попасть на небеса. ਸਭੁ ਕੋਈ ਚਲਨ ਕਹਤ ਹੈ ਊਹਾਂ — Sabh Koyi Chalan Khet Hai Uha(n). Но сам я не знаю, где это небо находится. ਨਾ ਜਾਨਉ ਬੈਕੁੰਠੁ ਹੈ ਕਹਾਂ — Na Jano Baikunth Hai Kha(n).','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2724,'','в конечном счёте побеждает простая логика гурбани','а не нелогичные, но громкие притязания духовенства на знание того, что никому не известно.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2725,'','наши бхагаты стояли против этих ложных притязаний','разрывали цепь подчинения и контроля, которую духовенство удерживало над людьми через нарратив о Рае и Аде.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2726,'','совершив это','став Божественным из человека — ਨਰ ਤੇ ਉਪਜਿ — Nar Tay Upaj.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2727,'','я завоевал для себя рай','ਸੁਰਗ ਕਉ ਜੀਤਿਓ — Surg Ko Jitiyeo — и нашёл лекарство, решение — ਸੋ ਅਵਖਧ ਮੈ ਪਾਈ — So Avkhad Mein Payi.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2728,'','сикх создаёт свой собственный рай','совершая Божественные дела, живя Божественной жизнью, воплощая Божественные добродетели. И в этом процессе он создаёт Рай для других тоже.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2729,'','когда перестаёшь жить духовностью рая и ада','начинаешь жить настоящим, свободным от страха и тревоги.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2730,'','когда перестаёшь ждать попасть в рай','начинаешь создавать свой собственный Рай здесь. И начинаешь жить в этом Раю уже сейчас.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2731,'','спасение','Мукти — Джеван Мукт','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2732,'','спасение, которое обещают после смерти','ਮੂਏ ਹੂਏ ਜਉ ਮੁਕਤਿ ਦੇਹੁਗੇ — Muey Huey Jao Mukat Dehogey — никто по-настоящему не знает. ਮੁਕਤਿ ਨ ਜਾਨੈ ਕੋਇਲਾ — Mukat Na Janey Koela — никто не знает этой Мукти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2733,'','то, что сделали бхагат бейни и бхагат намдев,','это отвержение понятия Спасения в загробной жизни. ਮਰਨ ਮੁਕਤਿ ਕਿਨਿ ਪਾਈ — Maran Mukat Kin Payee — кто когда-либо обрёл Спасение через смерть? Никто.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2734,'','гуру арджун','на странице 534 СГГС — прямо и недвусмысленно заявляет: он не хочет Спасения четырёхтысячелетнего старого холста:','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2735,'','духовенство может устать','ਥਾਕੇ — Thakay — читая и повторяя свои писания — ਪੜਿ ਪੜਿ ਪੰਡਿਤ — Parrh Parrh Pandit — и устать от молчаливого подвижничества — ਮੋਨੀ — Moni. Но, нарядившись в одеяния — ਭੇਖੀ — Bheykhi — Спасения они не обретут — ਭੇਖੀ ਮੁਕਤਿ ਨ ਪਾਈ — Bheykhi Mukt Na Payi.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2736,'','осознание творца внутри','здесь и сейчас — вот что важно. И достигается это через послания истинного Шабада.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2737,'','спасение в гурбани','это здесь и сейчас. В Гуру Грантх Сахиб оно называется ਜੀਵਨ ਮੁਕਤਿ — Jeevan Mukt. Слово ਜੀਵਨ — Jeevan — означает «жизнь», «пока живой», «в настоящей жизни». Мукти при жизни. Спасение при жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2738,'','в этом','великолепие Гурбани, её духовная мощь и величие.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2739,'','тот, кто осознаёт творца внутри себя','ਜਿਸੁ ਰਿਦੈ ਭਗਵੰਤੁ — Jis Ridhey Bhagwant — обретает Спасение здесь и сейчас — ਜੀਵਨ ਮੁਕਤਿ — Jeevan Mukat.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2740,'','обрести спасение здесь и сейчас','это значит быть духовно богатым — ਓਹੁ ਧਨਵੰਤੁ — Oh Dhanwant, духовно возвышенным — ਕੁਲਵੰਤੁ — Kulwant, духовно достойным — ਪਤਿਵੰਤੁ — Patwant.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2741,'','все три духовных состояния','здесь и сейчас.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2742,'','далее','этот стих на странице 449 СГГС:','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2743,'','этот стих','по существу определение понятия ДЖЕВАН МУКТ в Сикхи. Спасение здесь и сейчас достигается через умерщвление пороков в себе — в этой жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2744,'','понятие спасения в сггс','это ਜੀਵਨ ਮੁਕਤਿ — Jivan Mukt. Такое духовное состояние достигается здесь и сейчас — в этой жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2745,'','когда перестаёшь гнаться за спасением после смерти','начинаешь искать Спасение здесь и сейчас.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2746,'','суд','Дарга','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2747,'','по его учению, дарга','это Суд. Санскритский эквивалент Дарга — Дхарм Кшетра. Это место — место суда над душой после смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2748,'','дарга','это место, где выносится приговор отшедшей душе. Добродетельных отправляют на небеса, порочных — в ад, прочих возвращают в цикл реинкарнации.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2749,'','но где в гурбани прямое свидетельство того, что суд','внутри?','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2750,'','путь к просветлению о суде внутри','через Гур Шабд: ਗੁਰ ਸਬਦੀ ਦਰੁ ਜਾਣੀਐ Гур Шабди Дар Джанееай.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2751,'','голос нашей совести внутри','это голос Творца внутри.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2752,'','он сам','Голос нашей Совести внутри.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2753,'','плод','в заключительном стихе: ਅੰਮ੍ਰਿਤ ਕਾ ਰਸੁ ਆਇਆ ਮਨਿ ਵਸਿਆ ਨਾਉ Амрит Ка Рус Айя Мун Васья Нао.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2754,'','доброе я принимаю','ਖਰੇ ਪਰਖਿ ਖਜਾਨੈ ਪਾਈਅਨਿ Хрей Парх Кхаджанай Пайен. Нечистое отвергаю — ਖੋਟਿਆ ਨਾਹੀ ਥਾਉ Кхотья Нахи Тхао. И тогда суть духовной жизни пробуждается — ਅੰਮ੍ਰਿਤ ਕਾ ਰਸੁ ਆਇਆ ਮਨਿ ਵਸਿਆ ਨਾਉ Амрит Ка Рус Айя Мун Васья Нао.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2755,'','дибан','это Суд. Гхар — это «внутри», и в Гурбани это слово указывает именно на Сердце, на то, что находится внутри.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2756,'','по существу, пийарео, то, что сделала гурбани','она Освободила нас от всего нарратива о Дарга в загробной жизни, созданного на основе четырёхтысячелетнего старого холста.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2757,'','царь пребывает внутри','ਅੰਦਰਿ ਰਾਜਾ Андар Раджа. Его Трон — внутри. Суд — внутри. Всё это — в настоящем.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2758,'','начало сикхи в том, что творец','внутри. Если Творец внутри — Его Суд внутри. Если Суд внутри — Судья внутри. Судья — Голос Совести внутри. И всё это — в НАСТОЯЩЕМ.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2759,'','очевидно, что дхарм радж в гурбани','это совершенно иная концепция, никак не связанная с Дхарм Раджем четырёхтысячелетнего старого холста.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2760,'','второе значение','переопределённое. Дхарм Радж в контексте Гурбани — это Царство Дхармы, которое созидается внутри, здесь и сейчас.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2761,'','наша задача','как Сикхов Гурбани, Шри Гуру Грантх Сахиба — распознавать, в каком из двух контекстов употребляется слово «Дхарм Радж» в Гурбани.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2762,'','по преданию старого холста, яма дуты','это воины смерти, которые сопровождают Дхарм Раджа, когда тот является за душой умершего, и доставляют её на суд. А Читра Гупт — счетовод, ведущий запись всех дел человека в течение его жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2763,'','мой соединяющий с творцом гуру устранил мою тревогу','и покой снизошёл на мою жизнь. Мой Творец — Хранитель моей жизни, Он поставил заслон перед смертью.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2764,'','the creator','connecting Guru has brought about realization of the Creator whin. I thus have spiritual bliss the automatic elimination of the notion of Jum Doot .','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2765,'','таким образом, джум в гурбани','это синоним физической смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2766,'','в течение всей жизни яма','это Неизбежная Смерть, которая приходит в Хукм Творца. Она вписана в само устройство жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2767,'','итак, яма','это просто физическая смерть в пределах Его Хукм, в рамках Его Ржаа, Его Воли. Ничего больше.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2768,'','когда что','то неизбежно для всех — есть ли смысл этого бояться? Гуру Амардас говорит нам: нет смысла бояться того, что неизбежно.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2769,'','мой ум обрёл божественные добродетели','пороки оставили меня.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2770,'','итак, яма дуты переопределяются как наши пороки','потому что именно Пороки суть агенты нашей духовной смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2771,'','я укоренил в себе божественные добродетели','и моя духовность расцвела. Язва пороков исчезла.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2772,'','подводя итог, пийарео,','вот шабд, который выражает понимание Гурбани по этой теме:','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2773,'','о мой возлюбленный ум, прими духовность вездесущего','загрузи ценный товар Его Имени. О мой возлюбленный ум, ступи к устойчивым Вратам Хари.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2774,'','жаль, что наше духовенство','грантхи, парчараки, киртаниясы, раги — продолжают пересказывать эти истории из четырёхтысячелетнего старого холста, вместо того чтобы обращаться к Гурбани.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2775,'','первый','контекст до-1469-х верований: Яма Дуты в загробной жизни, Читра Гупт как счетовод дел, Дхарм Радж как судья — Гурбани критикует и разрушает их.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2776,'','второй контекст','ПЕРЕОПРЕДЕЛЁННЫЙ. ЯМА ДУТЫ в Гурбани — это ПОРОКИ. ЧИТРА ГУПТ в Гурбани — это наше СОЗНАНИЕ.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2777,'','читра гупт','это та ФОРМА (Читр) нашего существа, которая СКРЫТА (Гупт) — в отличие от нашего физического проявления. Это наше СОЗНАНИЕ — та часть нас, которая наблюдает, оценивает и ведёт запись наших мыслей, слов и поступков.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2778,'','прежде всего нам нужно рассмотреть до','1468-е верования, касающиеся Предков.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2779,'','подношения','постели, еда, предметы обихода, посуда — делаются либо в гурдваре, либо у рек и водоёмов.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2780,'','а в стихе','Рахао того же шабда Бхагат Кабир говорит следующее.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2781,'','но послания гурбани не остановили наше духовенство','грантхи, рагиев, киртаниясов — от пропаганды этих ритуалов.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2782,'','послание','УСТРАНИТЬ это противоречие. ОТВЕРГНУТЬ это лицемерие. И путь к этому — чтить предков, пока они живы, а не после смерти.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2783,'','когда ты перестаёшь гнаться за неправильным','у правильного появляется шанс настичь тебя.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2784,'','второй','когда ТА ЖЕ концепция упоминается как ПЕРЕОПРЕДЕЛЁННАЯ Концепция Гурбани. Переопределённое понятие смерти — это Духовная Смерть: смерть при жизни.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2785,'','язык и терминология те же','само слово не меняется. Но смысл, контекст и послание — совершенно разные.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2786,'','язык и терминология','те же. Слово по-прежнему СМЕРТЬ — или марн, маут и т.д. в Гурбани. Но контекст совершенно иной.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2787,'','другой','когда составители Гурбани хотят представить ПЕРЕОПРЕДЕЛЁННЫЙ смысл и понимание этой концепции.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2788,'','например, слово нарак суарг','рай и ад. Как узнать, когда Нарак Суарг используется в контексте критики, а когда — переопределения?','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2789,'','если послание стиха','КРИТИКА, ОСУЖДЕНИЕ, ОТВЕРЖЕНИЕ Нарак Суарг — как в этих стихах:','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2790,'','для примера рассмотрим концепцию тиртха','места паломничества до 1469 года. Тиртх — это «священное» место, часто у слияния рек или у озёр, в которое вложено религиозное значение.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2791,'','тиртх','место, куда идут ради внутреннего очищения.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2792,'','как сказано выше, оно встречается','как и любая другая концепция до 1469 года — в двух основных контекстах.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2793,'','хотя слово тиртх используется во всех трёх стихах','это никоим образом не утверждение тиртхов.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2794,'','если этот контекст игнорируется','происходят четыре вещи. Первое: Гурбани будет выглядеть противоречивой. Второе: Гурбани будет выглядеть так, будто поддерживает то, что она сама же отвергает. Третье: нас будут легко вводить в заблуждение. Четвёртое: духовенство возьмёт над нами власть.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2795,'','освободиться от этого четырёхтысячелетнего холста','значит освободиться от изнуряющих страхов загробного мира, которые держат нас в плену в жизни нынешней.','',NULL,'canvas_combined_ru',0.85,NULL);
INSERT INTO "words" VALUES(2796,'','сикхи','в данном тексте обозначает само учение Гуру Нанака, а не последователей (сикхов).','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2797,'','сикхизм','распространённый термин для обозначения традиции','используется преимущественно в академическом и внешнем контексте.',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2798,'','сггс / сггс','Sri Guru Granth Sahib / Шри Гуру Грантх Сахиб, священное писание Сикхи.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2799,'','шабд','Божественное Слово','духовный принцип и просветляющее послание Гурбани.',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2800,'','наам','Божественная сущность, присутствие и добродетельный принцип Творца.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2801,'','хукам','Божественный порядок, воля и закон бытия.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2802,'','сатгуру','Истинный Гуру','в контексте Сикхи — просветляющее руководство Божественным Словом.',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2803,'','мукти','освобождение','в Сикхи прежде всего как внутреннее освобождение при жизни.',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2804,'','дживан мукт','человек, достигший освобождения ещё при жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2805,'','дарга / даргах','«двор», «присутствие суда»','духовный термин, требующий понимания в контексте Гурбани.',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2806,'','дхарм радж','традиционный образ судьи','в книге рассматривается через переосмысление в свете Гурбани.',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2807,'','ава гаван','«приход и уход»','обычно связывается с циклом рождения и смерти, но в книге рассматривается заново.',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2808,'','нирмал','чистый, незамутнённый, свободный от духовных наслоений.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2809,'','это','повествование о портрете Сикхи. Точнее, это история холста, на котором портрет Сикхи обретает жизнь.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2810,'','холст','а им был человеческий УМ — уже был расписан тысячей образов.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2811,'','гуру нанак обнаружил, что человеческий ум','духовный холст людей его времени — был расписан образами рая и ада, 8,4 миллиона форм жизни после смерти, слуг смерти, ангелов смерти и круговорота рождений и смертей (Ava Gaun), перевоплощений.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2812,'','но было ещё кое','что. Существующий холст был сосредоточен на Смерти. Это был холст, одержимый жизнью после смерти и зацикленный на загробном мире.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2813,'','духовность гуру нанака','для ЗДЕСЬ и СЕЙЧАС.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2814,'','духовность гуру нанака была нирмал','чистой. Она была уникальной. Нирмал — потому что в ней не было загрязнений отринутого холста: ни “небес”, ни ада, ни 8,4 миллиона форм жизни, ни перевоплощений, ни судей, ни вестников смерти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2815,'','и прежде всего','нирмал потому, что она предлагала духовность для жизни в настоящем, а не для какого-то неизвестного и непознаваемого БУДУЩЕГО — будущего, которое никто никогда не видел и не переживал.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2816,'','тогда почему','можете вы спросить — ВСЕ концепции старого холста упоминаются в СГГС (Сири Гуру Грантх Сахиб)? ЕСЛИ старый холст действительно был отвергнут — зачем о нём вообще говорить?','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2817,'','дело в том, что холст','не физический. Физический холст можно уничтожить, смять и выбросить. Но мы говорим о ментальном холсте. А ментальный холст нельзя уничтожить, сжечь или забросить.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2818,'','подавляющее большинство нас, сикхов,','сикхи лишь внешне. Уникальны по облику. Но наш ОБРАЗ МЫШЛЕНИЯ сформирован 4000-летним старым холстом.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2819,'','способ, которым гуру нанак писал поверх него,','новаторский, изобретательный и удивительный. Это способ, которым пользуются, когда хотят перекрасить внутренние стены помещения.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2820,'','переопределение','вот путь. Правильный и верный путь. Единственный способ дать людям НОВОЕ МЫШЛЕНИЕ. Гуру Нанак переопределил всё это внутри страниц СГГС.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2821,'','если ответ хотя бы на один из этих вопросов','да, то нам следует знать: это — столпы отвергнутого холста, а не холста Гуру Нанака.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2822,'','духовность ритуалов','со старого холста. На холсте Гуру Нанака она заменяется духовностью Просветления.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2823,'','в этих классических текстах','по сути, выдумки, замаскированные под сакхи, в которых наши Гуру действуют и живут согласно концепциям старого, отвергнутого холста.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2824,'','подобное разложение','осуществляемое, потворствуемое, принимаемое и проповедуемое на протяжении длительного времени — производит следующий эффект. Истинный Холст Гуру Нанака оказывается подменён старым, отвергнутым холстом.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2825,'','наше духовенство','грантхи, раги, катхакары, проповедники и писатели — не просто держится за старый холст, но и проповедует его как подлинное Сикхи (учение).','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2826,'','и это','потому что мы проигнорировали тот факт, что все существующие концепции отвергнутого холста были ПЕРЕОПРЕДЕЛЕНЫ. Мы игнорируем переопределённые значения.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2827,'','во','первых — потряс само основание старого холста, разрушил два его столпа: смерть и страх перед тем, что после.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2828,'','первое, что делает гурбани','ещё ДО переопределения смерти — это даёт правильное, сбалансированное и реалистичное понимание физической смерти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2829,'','это выравнивание освобождает','ибо избавляет от страха перед выдуманным странствием и беспокойства о ложном суде.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2830,'','это выравнивание осмысленно','ибо говорит: живи в полную силу, здесь и сейчас, вплоть до момента неизбежной физической смерти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2831,'','ava gavan означает','цикл жизни и смерти. В контексте Гурбани это цикл духовной жизни и духовной смерти. Помните о переопределении. Именно переопределённые значения приведут нас к тем смыслам, которые Гурбани намеревается передать.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2832,'','фраза aye gya','приход и уход — относится к духовной жизни, духовной смерти и к циклу духовной жизни и духовной смерти соответственно, потому что следующая часть шлока содержит выражение Badhik Jio Bikaro.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2833,'','смерть, которая наступает из','за связанности пороками, — это духовная смерть.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2834,'','цикл, который возникает из','за связанности пороками, — это цикл ДУХОВНОЙ жизни и ДУХОВНОЙ смерти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2835,'','слова marta / marna / mar и mua','все означают смерть. В этом одном-единственном двустишии содержится 7 упоминаний смерти. Но из этих семи только одно употреблено в значении физической смерти. В остальных 6 случаях речь идёт о духовной смерти и смерти от пороков.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2836,'','в','третьих, Гурбани определяет физическую смерть как возвращение к нашим истокам.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2837,'','фокус гуру нанака','на предотвращении духовной смерти, а его устремление — на том, чтобы избежать смерти нашей совести.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2838,'','и если мы хотим по','настоящему понять Сикхи Гуру Нанака, нам нужно понять НОВЫЕ значения — ПЕРЕОПРЕДЕЛЁННЫЕ смыслы — этих концепций.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2839,'','первое','Познаваемость. Утверждается, что природа и характер жизни после смерти полностью известны. Что она хорошо изучена. Что о ней можно рассуждать с абсолютной уверенностью и авторитетностью.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2840,'','второе','путь описан с высокой степенью конкретности. Нарратив таков: душа отправляется в невероятное путешествие. Путешествие, у которого есть чёткие маршруты, вехи и пункты назначения.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2841,'','третье','определены этапы посмертного пути. Четырёхтысячелетний холст содержит детали вплоть до количества дней на каждом его отрезке.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2842,'','четвёртое','душа усопшего предстаёт перед Судом. Согласно нарративу, душе требуется один год, то есть 365 дней — один Барас — чтобы добраться до места Суда.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2843,'','пятое','душе усопшего назначается один из трёх путей: (1) на небеса, (2) в один из 21 вида ада, или (3) снова в жизнь — в форме одного из 8,4 миллиона видов живых существ.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2844,'','шестое','последние обряды: похороны, кремация или погребение — играют ключевую роль, поскольку именно они готовят душу к этому путешествию.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2845,'','и наконец','весь этот цикл повторяется.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2846,'','всё это','о путешествии, которое НИКТО не совершал, и о месте назначения, откуда никто не вернулся, чтобы поведать об увиденном.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2847,'','самое же леденящее','это то, что именно этот нарратив о загробной жизни, взятый с четырёхтысячелетнего холста, продолжает звучать на большинстве сикхских религиозных церемоний.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2848,'','подавляющее большинство сикхов справляют барси','годовщины смерти — хотя сама концепция барси основана именно на четырёхтысячелетнем холсте.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2849,'','первое, что делает гурбани,','это подвергает Критике саму концепцию Познаваемости, выдвинутую четырёхтысячелетним холстом.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2850,'','метафора','это поле. Последняя фаза поля — жатва. Отсюда термин — Lavee Aya Kheyt — «жатва пришла на поле».','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2851,'','если бы он одобрял этот нарратив','критики не было бы. Но она есть. И она содержится в том же стихе.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2852,'','фраза','Bheyt Cheyt Har — и в особенности употребление слова ХАР с сихари весьма примечательно. Слово ХАР здесь стоит в объектном падеже и означает — Бог, то есть Творец.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2853,'','вот ещё один стих гуру нанака','на странице 648 СГГС.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2854,'','воздух','к воздуху. Вода — к воде. Прах — к праху.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2855,'','что касается самой жизни','она тоже возвращается к своему Источнику — к Творцу.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2856,'','если бы существовали какие','либо исключения, условия, процессы, ограничения — мы вправе спросить: каковы они? Где в Гурбани они описаны? Можно ли указать стих, параграф, страницу?','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2857,'','вот он','Цикл Жизни. Приходит по Хукаму. Уходит по Хукаму.  — Hukmaiy Aveiy Hukmaiy Javeiy Hukmaiy Rhaiy Smayee.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2858,'','бхагат кабир выражает это следующим образом','на странице 1103 СГГС.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2859,'','суть в том, что я слился со своим творцом','внутри — ЗДЕСЬ и СЕЙЧАС.  — Sunney Sunn Miliya Samdarsi. Равно видящий — тот, кто достиг слияния с Запредельным.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2860,'','когда нечто происходит снова и снова','тогда, по определению, оно может обесцениться. Но уж точно не быть бесценным. Именно поэтому - бесценно то, что бывает лишь однажды.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2861,'','но человеческая жизнь','только РАЗ. Потому она и бесценна.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2862,'','чаураси лакх','8,4 Миллиона Форм Жизни','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2863,'','sweta swartar upnishad','древнем тексте, написанном примерно за 4000 лет до наших дней.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2864,'','пугающие подробности этого путешествия','которое никто никогда не совершал — содержатся в многочисленных концептуальных текстах старого холста.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2865,'','наглядно это подтверждает следующий стих из гурбани','на странице 237 СГГС:','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2866,'','используемое слово','— Anuk — означает «бесчисленные, неисчислимые, бесконечные».  — Anuk Joan — означает бесчисленные формы жизни. Не 8,4 миллиона. Бесчисленные.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2867,'','второй стих содержит упоминание ряда животных','— Kookreh Sookreh Gardhbey Kakeh — и  — Sarpney: собака, свинья, осёл, ворона, змея. Все они — животные формы жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2868,'','если же взглянуть на первый стих','там мы видим ПЕРЕОПРЕДЕЛЕНИЕ в самом ясном виде.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2869,'','ключевые слова здесь','— Jo Pranni — «тот человек». Определённый тип человека. Живой человек — — Pranni — прямо сейчас, здесь.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2870,'','и есть слово','Tul — означающее «подобный, сравнимый с, схожий по характеру».','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2871,'','итак,','Kookreh Sookreh Gardhbey Kakeh — и — Sarpney — собака, свинья, осёл, ворона, змея — это НЕ буквальные формы жизни в загробном мире. Это метафоры УМСТВЕННЫХ СОСТОЯНИЙ, в которых живут люди — ЗДЕСЬ и СЕЙЧАС.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2872,'','упоминание животных','— Sookar Suan Gardhab Manjara — служит отсылкой к УМСТВЕННЫМ СОСТОЯНИЯМ ЧЕЛОВЕКА. Свинья символизирует жадность. Осёл — упрямство. Собака — раболепие и услужливость. Кошка — лесть.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2873,'','вот ещё один стих','на странице 1418 СГГС:','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2874,'','те люди, которые не познали творца внутри себя','— Satgur Purakh Na Sayveyo — и не размышляли над Шабдом —  — Shabd Na Keeto Vichar — таких Гуру называет не живущими в человеческой форме жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2875,'','следующая часть','— Psu Haon Kar Janni — означает: я низвёл свою жизнь — свою человеческую жизнь —  — Kar Janni — до уровня животного.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2876,'','первый стих','— Mayray Sahiba Kaonn Janney Gun Tayray — о Божественных Добродетелях Творца. Никто не способен их постичь. Точно так же,  — Khay Na Janni Augunn Mayray — мои пороки тоже невыразимы.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2877,'','все эти примеры','формы жизни:  — Rukh Birekh, Psu, Naag, Pankh — деревья, растительность, животные, змеи, птицы. И все они —  — Kaytay — бесчисленны.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2878,'','вот ещё один набор стихов','на странице 802 СГГС:','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2879,'','упоминание','Psu — это НЕ 8,4 миллиона форм жизни в загробном мире. Это наша  — Psu-punna — наше животное СОСТОЯНИЕ РАЗУМА, в котором мы живём здесь и сейчас.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2880,'','очевидно, что смерть здесь','это ДУХОВНАЯ СМЕРТЬ — — Mirtak Deh — которая и составляет заботу Гурбани. И ФОРМЫ ЖИЗНИ —  — Avat Jaat Joni — это СОСТОЯНИЯ РАЗУМА, в которых мы блуждаем здесь, в этой жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2881,'','стих рахао содержит слова','Apnay Karm Ki Gut — означающие: вот таково положение дел — — Ki Gut — с моими деяниями. Когда во мне умирает человек —  — Nru Mreiy — то есть человечность, гуманность — он никому не нужен и бесполезен —  — Nur Kaam Na Aveiy.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2882,'','по существу, то, что происходит в гурбани,','это ПЕРЕОПРЕДЕЛЕНИЕ концепции 8,4 миллиона форм жизни: из физического измерения (после смерти) — в духовное (здесь и сейчас). Это переход от внешнего к внутреннему. От посмертного — к ныне живому.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2883,'','то, что говорят все приведённые выше стихи,','что внутри нас есть Зоопарк. Зоопарк умственных состояний: состояние собаки, состояние свиньи, состояние осла, состояние вороны, состояние змеи, состояние дерева, состояние камня, состояние демона — и состояние человека, состояние просветлённого.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2884,'','гюго также сказал кое','что ещё. Он сказал: «Нет ничего сильнее идеи, время которой пришло». Гуру Нанак предложил нам духовность, время которой давно пришло. Ещё в 1469 году.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2885,'','мы можем изменить это в нашей жизни','признав, что время Сикхи Гуру Нанака пришло. Мы можем изменить — даже если наше духовенство не хочет или не способно.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2886,'','реинкарнация','Ава Гаван','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2887,'','самое леденящее','то, что именно этот нарратив о Реинкарнации из четырёхтысячелетнего старого холста продолжает звучать на большинстве сикхских религиозных церемоний.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2888,'','когда всё многообразие видов было создано впервые','до которого не было никаких видов,  — Jub Kach Na Sio — какие тогда деяния совершила только что созданная душа? Никаких. Ни единого. Ни плохих, ни хороших.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2889,'','раз не было никаких деяний','что именно записывал так называемый Читр Гупт? Какие деяния он докладывал Дхарм Раджу на суде первых душ? Ответ: никакие. Потому что ни первых деяний, ни первого суда не было.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2890,'','если сикх гурбани думает самостоятельно','одного этого двустишия достаточно, чтобы разрушить весь сфабрикованный нарратив о Читр Гупте, Дхарм Радже и суде над деяниями.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2891,'','второе, что делает гурбани,','это ясно говорит: жизнь, которую мы имеем ЗДЕСЬ и СЕЙЧАС, является Единственной и Неповторимой жизнью.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2892,'','слово','Ehi — означает «только это». Только это и ничего более. Слова — Tayra Ausar — означают «Твоя Возможность». А слово  — Baar — означает «время, срок, момент».','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2893,'','здесь одно лишь слово','Ehi — и одна фраза  — Ehi Tayra Ausar — достаточны, чтобы полностью и бесповоротно разрушить всю концепцию Реинкарнации.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2894,'','что это означает','«прийти снова»?  — Bahur Hum Kahe(n) Aveh(n)gay.  — Bahur — означает «снова, во второй раз». Кабир задаёт прямой вопрос: что такое «прийти обратно»? Каковы основания для самой концепции возвращения?','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2895,'','приход и уход','в Его Хукаме —  — Aavan Jaana Hukm Tisaiy Ka — и познав Хукам —  — Hukmeiy Bujh — мы сливаемся —  — Smaveh(n)gay.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2896,'','слияние','это антитеза возвращения. Слияние — это противоположность Реинкарнации. Когда сливаешься —  — не возвращаешься. Потому что слияние — это именно слияние.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2897,'','если смерть переопределяется','то ЗАГРОБНАЯ ЖИЗНЬ и то, что ПОСЛЕ Смерти, тоже переопределяется как то, что происходит ПОСЛЕ духовной смерти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2898,'','цель','вырваться из этого цикла и пребывать постоянно в Духовной Жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2899,'','задача','стать Аджуни — то есть выйти за пределы цикла духовной жизни и духовной смерти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2900,'','реинкарнация или ава гаван гурбани','в этом шабаде — это цикл, происходящий ВНУТРИ меня. Внутри моего разума. В этой жизни. ЗДЕСЬ и СЕЙЧАС.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2901,'','итак, ава гаван, или цикл','это цикл, качающийся между состояниями Божественных Добродетелей и Человеческих Пороков. Это колебание происходит внутри нас — ЗДЕСЬ и СЕЙЧАС, в этой жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2902,'','переопределённая реинкарнация гурбани','это процесс, в котором я снова и снова рождаюсь —  — Fun Fun — в состояниях пороков. И снова и снова — умираю духовно.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2903,'','ава гаван в гурбани','это Цикл, качающийся как маятник между Духовной Жизнью — на основе Добродетелей — и Духовной Смертью — на основе Пороков. Цикл происходит ЗДЕСЬ и СЕЙЧАС. В нас. В этой жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2904,'','гуру арджун излагает','в самых ясных словах — что такое Ава Гаван или Реинкарнация в Гурбани. Это качание между Камом, Кродхом, Лобхом, Мохом —  — Kam Krodh Lobh Moh — похотью, гневом, жадностью, привязанностью — и Бхагати, Любовью к Творцу, Симраном — — Sda Ava Gavan — это и есть вечный Ава Гаван.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2905,'','три слова','— Bhrm Bheyd Bho — означают иллюзию, заблуждение и страх. Все они — негативные умственные состояния, из-за которых мы блуждаем в Ава Гаван —  — Aavat Jaat Na Jani.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2906,'','итак, цикл','это было колебание между просветлением и иллюзией. Конец цикла выражен словами  — Katee Bayri Pgeh Teh Gur Kini Band Khlas — Гуру разрезал оковы на ногах — тюрьма разрушена, узник освобождён.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2907,'','слова','Manmukh Garbh Juni Nit Pauda Jio — важны и значимы. Они означают: Манмукх снова и снова входит в форму жизни чрева — Гарбх Джуни — Nit — постоянно. Манмукх — это тот, кто следует своему собственному уму, а не Гуру.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2908,'','и причина этого','в БАЗОВОМ и ФУНДАМЕНТАЛЬНОМ принципе Холста Сикхи Гуру Нанака.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2909,'','поэтому причина переопределения','в том, чтобы укоренить понятие 8,4 миллиона, понятие Джун, понятие Реинкарнации и Ава Гаван — в ЗДЕСЬ и СЕЙЧАС. Чтобы духовность работала для нас именно здесь и сейчас.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2910,'','когда ты перестаёшь жить духовностью второй жизни','ты начинаешь жить Единственной и Неповторимой Жизнью в Полную Силу.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2911,'','в следующих частях','части 6 из 12 — будут рассмотрены концепции Рая и Ада. Будет предложено новое, переопределённое Гурбани значение этих концепций.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2912,'','если сикх думает самостоятельно','одного этого двустишия достаточно, чтобы разрушить весь сфабрикованный нарратив о Рае и Аде.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2913,'','что может быть яснее','Dou Radey — «я отвергаю оба»? Что может быть яснее  — Hum Kahu Kee Kaan Na Kadhtey — «я ни от кого не завишу»?','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2914,'','гуру арджун джи предлагает ещё одну критику','объясняющую, зачем вообще понадобилась эта выдумка. Стих на странице 295 СГГС:','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2915,'','чтобы этот нарратив работал','то есть чтобы заставить людей совершать одобренные духовенством деяния и избегать запрещённых — нужны были морковь и кнут. Рай — морковь. Ад — кнут.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2916,'','нарратив','— Ktha Kahanni — данный миру Ведами —  — Beydi Aanni — таков: есть благочестивые деяния и греховные. Отдаёшь больше, чем получаешь — попадешь в Рай, а если получаешь больше, чем отдаёшь: попадаешь в Ад. Вот такой нарратив.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2917,'','веды провозглашают','— Beyd Pukarey — что благочестивые и греховные деяния —  — Punn Paap — являются определяющими критериями для Рая и Ада. Что посеешь — то и пожнёшь. Но Гуру Нанак здесь критикует этот нарратив, а не принимает его.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2918,'','все','— Sabh Koyi — утверждают, что знают, как попасть на небеса (Байкунтх).','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2919,'','нарратив о рае и аде','именно нарратив. Его создали люди, которые ничего не знают, кроме как сочинять нарративы ради контроля.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2920,'','в конечном счёте побеждает простая логика гурбани','а не нелогичные, но громкие притязания духовенства на знание того, что никому не известно.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2921,'','наши бхагаты стояли против этих ложных притязаний','разрывали цепь подчинения и контроля, которую духовенство удерживало над людьми через нарратив о Рае и Аде.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2922,'','совершив это','став Божественным из простого человека —  — Nar Tay Upaj.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2923,'','я завоевал для себя рай','— Surg Ko Jitiyeo — и нашёл лекарство, решение — — So Avkhad Mein Payi.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2924,'','сикх создаёт свой собственный рай','совершая Божественные дела, живя Божественной жизнью, воплощая Божественные добродетели. И в этом процессе он создаёт Рай для других тоже.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2925,'','когда перестаёшь жить духовностью рая и ада','начинаешь жить настоящим, свободным от страха и тревоги.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2926,'','когда перестаёшь ждать попасть в рай','начинаешь создавать свой собственный Рай здесь. И начинаешь жить в этом Раю уже сейчас.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2927,'','в следующем выпуске','части 7 из 12 — будут рассмотрены концепции Спасения, или Мукти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2928,'','спасение','Мукти — Дживан Мукт','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2929,'','спасение, которое обещают после смерти','— Muey Huey Jao Mukat Dehogey — никто по-настоящему не знает.  — Mukat Na Janey Koela — никто не знает этой Мукти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2930,'','человеческая жизнь растрачена','— Thaaka Tej. Ум не перестаёт блуждать —  — Udeya Mun Pankhee. Нет ни внутреннего покоя, ни удовлетворения.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2931,'','то, что сделали бхагат бейни и бхагат намдев,','это отвержение понятия Спасения в загробной жизни.  — Maran Mukat Kin Payee — кто когда-либо обрёл Спасение через смерть? Никто.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2932,'','гуру арджун','на странице 534 СГГС — прямо и недвусмысленно заявляет: он не хочет Спасения четырёхтысячелетнего старого холста:','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2933,'','чтение писаний, молчание, священная одежда','всё это внешнее. Устать от этого можно, но освобождения не получить. Безумен мир без бхакти. Только Шабд истинный соединяет. (c)','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2934,'','духовенство может устать','— Thakay — читая и повторяя свои писания —  — Parrh Parrh Pandit — и устать от молчаливого подвижничества —  — Moni. Но, нарядившись в одеяния —  — Bheykhi — Спасения они не обретут —  — Bheykhi Mukt Na Payi.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2935,'','осознание творца внутри','здесь и сейчас — вот что важно. И достигается это через послания истинного Шабда.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2936,'','спасение в гурбани','это здесь и сейчас. В Гуру Грантх Сахиб оно называется  — Jeevan Mukt. Слово  — Jeevan — означает «жизнь», «пока живой», «в настоящей жизни». Мукти при жизни. Спасение при жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2937,'','в этом','великолепие Гурбани, его духовная мощь и величие.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2938,'','что может быть яснее, чем слова гуру арджуна','Mukt Na Chaho — я не хочу вашего Спасения? Что может быть яснее вопроса Бхагата Бейни  — Maran Mukat Kin Payee — кто когда-либо обрёл Спасение через смерть?','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2939,'','тогда как слова','Maran Mukt — «Спасение через смерть» — встречаются в СГГС лишь в одном стихе, слова  — Jeevan Mukt — «Спасение при жизни» — встречаются в одиннадцати стихах.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2940,'','тот, кто осознаёт творца внутри себя','— Jis Ridhey Bhagwant — обретает Спасение здесь и сейчас —  — Jeevan Mukat.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2941,'','обрести спасение здесь и сейчас','это значит быть духовно богатым —  — Oh Dhanwant, духовно возвышенным —  — Kulwant, духовно достойным —  — Patwant.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2942,'','все три духовных состояния','здесь и сейчас.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2943,'','далее','этот стих на странице 449 СГГС:','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2944,'','этот стих','по существу определение понятия ДЖИВАН МУКТ в Сикхи. Спасение здесь и сейчас достигается через умерщвление пороков в себе — в этой жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2945,'','стоит отметить, что','Gun Gavey — это не пение добродетелей вслух. Добродетели не поют, не декламируют и не воспевают. Добродетели воплощают в жизни.  — Gun Gavey — значит жить добродетелями Творца в своей повседневной жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2946,'','каков плод','Jivan Mukt?','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2947,'','вместо этого','постоянное блаженство, без разлучения —  — Sda Anand Teh Nahi Biog.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2948,'','понятие спасения в сггс','это  — Jivan Mukt. Такое духовное состояние достигается здесь и сейчас — в этой жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2949,'','когда перестаёшь гнаться за спасением после смерти','начинаешь искать Спасение здесь и сейчас.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2950,'','в следующей главе','части 8 из 12 — будут рассмотрены концепции Даргаха, или Суда в загробной жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2951,'','по учению старого холста, дарга','это Суд. Санскритский эквивалент Дарга — Дхарм Кшетра. Это место — место суда над душой после смерти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2952,'','дарга','это место, где выносится приговор отошедшей душе. Добродетельных отправляют на небеса, порочных — в ад, прочих возвращают в цикл реинкарнации.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2953,'','суд','там, где Судья, там, где Царь.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2954,'','но где в гурбани прямое свидетельство того, что суд','внутри?','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2955,'','путь к просветлению о суде внутри','через Гуру Шабд:     Gur Shabdi Dar Janeeaiy','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2956,'','голос нашей внутренней совести','это Голос Творца внутри.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2957,'','он сам','Голос нашей Внутренней Совести.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2958,'','совесть','это Суд.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2959,'','этот стих говорит о характере и качестве  parakh','оценки или суда, который происходит внутри нашей Совести как голоса Творца внутри. Характер этого суда —  Sda Sach Niao.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2960,'','niyao','означает Справедливость.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2961,'','sda','означает постоянная, без исключений.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2962,'','sach','означает вечная, принадлежащая вечному Творцу.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2963,'','результат','в последнем стихе:','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2964,'','добро и зло, истина и ложь, реальное и нереальное','я сужу внутри своей Совести на основе  Gur Shabdi Dar Janeeaiy.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2965,'','я впитываю добро','Khrey Parkh Khajaneiy Payien.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2966,'','я отбрасываю зло','Khotia Nahi Thao.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2967,'','с другой стороны, если мы принимаем, что дарга','это внешняя сущность в загробной жизни, а суд вершится некой сущностью там — тоже в загробной жизни — тогда суть этого НЕ будет Божественностью, а страхом, тревогой, беспокойством и ужасом. Это не строительные блоки духовности в Здесь и Сейчас.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2968,'','таков суд творца, который находится внутри совести','Vasiya Bhagtan Kaiy Hirdaiy. Суд — внутри Совести. Настолько, что все остальные ничтожные суды —  Rehndey Kuhndey — исчезают при таком осознании —  Sabh Bhagtan Agaiy Khalvaiya.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2969,'','царь внутри','Ander Raja. Его Трон, на котором Он восседает, внутри —  Ander Raja Takhat Hai. Справедливость, закон, правила, суд — тоже внутри —  Ander Raja Takhat Hai Apey Krey Niaao.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2970,'','начало сикхи в том, что творец','внутри. Если Творец внутри — Его Суд внутри. Если Суд внутри — Судья внутри. Судья — Голос Совести внутри. И всё это — в НАСТОЯЩЕМ.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2971,'','очевидно, что дхарм радж в гурбани','это совершенно иная концепция, никак не связанная с Дхарм Раджем четырёхтысячелетнего старого холста.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2972,'','pandit mulaan chhaadey do','oo. (1) Rahaaau.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2973,'','второе значение','переопределённое. Дхарм Радж в контексте Гурбани — это Царство Дхармы, которое созидается внутри, здесь и сейчас.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2974,'','наша задача','как Сикхов (учеников) Гурбани, Шри Гуру Грантх Сахиба — распознавать, в каком из двух контекстов употребляется слово «Дхарм Радж» в Гурбани.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2975,'','по преданию старого холста, яма дуты','это слуги смерти, которые сопровождают Дхарм Раджа, когда тот является за душой умершего, и доставляют её на суд. А Читра Гупт — счетовод, ведущий запись всех дел человека в течение его жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2976,'','мой соединяющий с творцом гуру устранил мою тревогу','и покой снизошёл на мою жизнь. Мой Творец — Хранитель моей жизни, Он поставил заслон перед смертью.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2977,'','итак, яма','это просто физическая смерть в пределах Его Хукама, Его Воли. Ничего больше.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2978,'','когда что','то неизбежно для всех — есть ли смысл этого бояться? Гуру Амардас говорит нам: нет смысла бояться того, что неизбежно.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2979,'','мой ум обрёл божественные добродетели','пороки оставили меня.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2980,'','итак, яма дуты переопределяются как наши пороки','потому что именно Пороки суть агенты нашей духовной смерти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2981,'','подводя итог, дорогие,','вот шабд, который выражает понимание Гурбани по этой теме:','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2982,'','жаль, что наше духовенство','грантхи, парчараки, киртаниясы, раги — продолжают пересказывать эти истории из четырёхтысячелетнего старого холста, вместо того чтобы обращаться к Гурбани.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2983,'','первый','контекст до-1469-х верований: Яма Дуты в загробной жизни, Читра Гупт как счетовод дел, Дхарм Радж как судья — Гурбани критикует и разрушает их.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2984,'','второй контекст','ПЕРЕОПРЕДЕЛЁННЫЙ. ЯМА ДУТЫ в Гурбани — это ПОРОКИ. ЧИТРА ГУПТ в Гурбани — это наше СОЗНАНИЕ.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2985,'','читра гупт','это та ФОРМА (Читр) нашего существа, которая СКРЫТА (Гупт) — в отличие от нашего физического проявления. Это наше СОЗНАНИЕ — та часть нас, которая наблюдает, оценивает и ведёт запись наших мыслей, слов и поступков.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2986,'','подношения','постели, еда, предметы обихода, посуда — делаются либо в гурдваре, либо у рек и водоёмов.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2987,'','а в стихе','Рахао того же шабда Бхагат Кабир говорит следующее.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2988,'','но послания гурбани не остановили наше духовенство','грантхи, рагиев, киртаниясов — от пропаганды этих ритуалов.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2989,'','послание','УСТРАНИТЬ это противоречие. ОТВЕРГНУТЬ это лицемерие. И путь к этому — чтить предков, пока они живы, а не после смерти.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2990,'','когда ты перестаёшь гнаться за неправильным','у правильного появляется шанс настичь тебя.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2991,'','второй','когда ТА ЖЕ концепция упоминается как ПЕРЕОПРЕДЕЛЁННАЯ Концепция Гурбани. Переопределённое понятие смерти — это Духовная Смерть: смерть при жизни.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2992,'','язык и терминология те же','само слово не меняется. Но смысл, контекст и послание — совершенно разные.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2993,'','язык и терминология','те же. Слово по-прежнему СМЕРТЬ — или марн, маут и т.д. в Гурбани. Но контекст совершенно иной.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2994,'','другой','когда составители Гурбани хотят представить ПЕРЕОПРЕДЕЛЁННЫЙ смысл и понимание этой концепции.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2995,'','например, слова нарак сураг','рай и ад. Как узнать, когда Нарак Сураг используется в контексте критики, а когда — переопределения?','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2996,'','если послание стиха','КРИТИКА, ОСУЖДЕНИЕ, ОТВЕРЖЕНИЕ Нарак Суарг — как в этих стихах:','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2997,'','для примера рассмотрим концепцию тиртха','места паломничества до 1469 года. Тиртх — это «священное» место, часто у слияния рек или у озёр, в которое вложено религиозное значение.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2998,'','тиртх','место, куда идут ради внутреннего очищения.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(2999,'','как сказано выше, оно встречается','как и любая другая концепция до 1469 года — в двух основных контекстах.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(3000,'','хотя слово тиртх используется во всех трёх стихах','это никоим образом не утверждение тиртхов.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(3001,'','если этот контекст игнорируется','происходят четыре вещи.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(3002,'','освободиться от этого четырёхтысячелетнего холста','значит освободиться от изнуряющих страхов загробного мира, которые держат нас в плену в жизни нынешней.','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(3003,'','для перевода отсканируйте qr','код в приложении вашего банка','',NULL,'concepts_sikhi',0.85,NULL);
INSERT INTO "words" VALUES(3004,'','первый принцип','переход от буквального к духовному','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3005,'','чтобы описать духовную эмоцию','используется мирской язык любви.','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3006,'','как итог, духовное послание стихов','сокрыто','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3007,'','sabaiai jag','идиома относящаяся ко всему человечеству','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3008,'','uche char kai','это идиома означающая возвышенное состояние ума','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3009,'','ghar ghar','метафорически, каждый человек.','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3010,'','eha ag','это огонь мирских желаний. Почему? Это вытекает из контекста следующего стиха, который будет рассмотрен чуть ниже.','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3011,'','мои боль и страдания','не уникальны. Это часть и загадка жизни. Это то, что делает нас людьми во всем человечестве.','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3012,'','послание','духовное. Язык - мирской.','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3013,'','конечная цель','стать посланием, стать бани, стать добродетелью.','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3014,'','mar jau','состояние смерти','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3015,'','реализация божественных добродетелей','вот что (действительно) называется сложным.','',NULL,'course_1',0.85,NULL);
INSERT INTO "words" VALUES(3016,'','для понимания смысла','авторы Гурбани придумали указатели - Рахао.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3017,'','как мы уже знаем из предыдущего урока','необходимо переходить от буквального значения к метафорическому. Рахао буквально переводится как пауза. В действительности, это не только пауза. Что означает это слово?','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3018,'','в сукхмани','сотни стихов, но только один с рахао. Почему нужно размышлять именно над ним?','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3019,'','наша задача','выяснить, что означает “Рахао”, когда мы переходим на другую сторону метафоричного смысла. Для этого нам нужно опираться на контекст (3-ий принцип 3-го урока).','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3020,'','это','РАХАО.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3021,'','остановиться, stop','имеет контекст, это знак который установили на перекрестке. Остановись, посмотри налево, направо, и едь дальше. Остановиться - значит ехать.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3022,'','одна из особенностей поэзии','это рифма. Вспомним предыдущий урок: jag рифмуется с ag, и так далее.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3023,'','во','вторых, каждый шабд написан в определенном поэтическом рааге, и имеет музыкальную составляющую или музыкальную функцию (musical composition). Составляющая которую нужно петь.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3024,'','dhnasri','это название рааги. “Главы” Сири Гуру Грантх Сахиб основаны на Раагах. Всего 32 раги - 32 главы.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3025,'','порядковый номер','это “номер” Гуру. И каждый из них использовал одно и то же имя - Нанак. Первый Нанак, Второй Нанак, Третий Нанак.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3026,'','кто','то подумает: “нам нужно название!”. Хочется понять о ком это.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3027,'','эти числа','система нумерации. Их задача предотвратить добавление или удаление шабдов из текста. Эти числа не влияют на смысл. Логика чисел - от меньшего к большему. Локальный контекст, контекст произведения, контекст того или иного автора бани в этом произведении.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3028,'','таким образом, чтобы понять о чем сообщение','нужно посмотреть на его название.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3029,'','с поэтической точки зрения','название стихотворения, не являющееся буквально частью стихотворения. Это часть, стоящая особняком','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3030,'','с музыкальной точки зрения','это припев','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3031,'','с духовной','это смысл','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3032,'','что бы ни просили у своего владыки','то Он и даёт.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3033,'','заглавный стих, первый стих, строфа','эквивалентен РАХАО. В нём содержится суть послания.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3034,'','соединяющий','с-Создателем Гуру направляет меня на Духовном Пути. Его благосклонностью, Он соединяет меня с Ним, обнимает и устраняет мои пороки.','',NULL,'course_2',0.85,NULL);
INSERT INTO "words" VALUES(3035,'','понимание гурбани','Часть 3: Контекст','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3036,'','переход от буквального к духовному','фундамент.','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3037,'','рахао','тема/припев/суть (gist).','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3038,'','контекст','текущая лекция.','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3039,'','бхаи харджиндер сингх','это известный сикхский раги (исполнитель киртана). Он также известен как Бхай Харджиндер Сингх Шринагар-вале, потому что начал свою карьеру в Шринагаре.','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3040,'','выделенное жирным зелёным цветом','это настоящее Рахао.','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3041,'','выделенное жирным красным цветом','это то что использует вместо Рахао упомянутый в видео рааги. Это прямое нарушение указаний Гуру по поводу Киртана. Также здесь отбрасывается часть цельной строки.','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3042,'','тот же единый','Опора всего сущего, всех форм жизни. Фраза «ਲਖ ਚਉਰਾਸੀਹ / 8,4 млн» — санатанская культурная формула, которой гуру пользуется как метафорой «бесчисленного множества», а не как буквальным подсчётом.','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3043,'','освобождение','это тут-и-сейчас: выход из «режима нехватки» в доверие Хукам, в сантокх (довольство) и благодарное действие.','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3044,'','чтобы опровергнуть идею, её нужно назвать','иначе слушатель не поймёт, что именно отвергается.','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3045,'','ниже','последовательный перевод видео «Understanding Gurbani — Part 3: Context (Контекст)». Я перевожу абзац за абзацем, сохраняя ход мысли автора и ключевые термины (Рахау, шабад, Хукам и т. п.).','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3046,'','теперь','к «спорным» строкам (о 8,4 млн и предначертанности).','',NULL,'course_3',0.85,NULL);
INSERT INTO "words" VALUES(3047,'','понимание гурбани','Часть 4: Для Себя: Принцип Адресата – Гурбани про нас, а не про других людей','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3048,'','второй','принцип «Рахау»','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3049,'','третий','контекст. Ссылки на все три видео есть в описании ниже.','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3050,'','желание контролировать то, что происходит снаружи','это религия. В этом разница между религией и духовностью:','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3051,'','религия','про контроль внешнего','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3052,'','духовность','про контроль внутреннего.','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3053,'','друзья, то, что позади нас, и то, что впереди нас','мелочи по сравнению с тем, что внутри нас. Вся жизнь там, снаружи, продолжается и без меня. Но важно то, чтобы моя жизнь продолжалась внутри меня.','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3054,'','brahmand','«во вселенной»,','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3055,'','pind','«внутри моего тела / меня».','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3056,'','то, что снаружи во вселенной,','находится внутри меня. Но это осознаётся через внутреннее присвоение (internalization): нужно внутренне «впитать» факт, что вселенная снаружи — внутри меня. Этот шабад принадлежит Бхагату Пипе.','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3057,'','а творец внутри меня','тот, который определён Гуру Нанаком и Гурбани: Бог духовности. Творец «снаружи» может «управлять раем и адом где-то там», но Творец внутри меня управляет мной. Он определяет, будет ли у меня райская жизнь внутри или ад внутри.','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3058,'','mann','«ум».','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3059,'','когда мы неверно говорим, будто смысл','«не спорьте с глупцами», мы уже вынесли суждение, что другой человек — «глупец». Но Гуру Нанак говорит: не осуждай никого. Суждения в Гурбани предназначены для Я, а не для мира снаружи.','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3060,'','он видит и слышит','всегда рядом','а я, глупец, считал(а) Его далёким, о!',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3061,'','кто','то стал алкоголиком, преступником или мошенником — потому что Бог «заставил его сбиться с пути». И наши переводчики скажут: «Это Хукам','ничего не происходит без Его Хукама; даже лист не шевельнётся без Его воли».',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3062,'','jo','«те моменты моей жизни»','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3063,'','satgur','«соединяющий с Творцом Гуру»','',NULL,'course_4',0.85,NULL);
INSERT INTO "words" VALUES(3064,'','дхрува','святой индуизма, великий преданный Вишну,','',NULL,'custom_custom_examples_how_to_work_with_voc',0.85,NULL);
INSERT INTO "words" VALUES(3065,'','keytia','множества (женский род)','',NULL,'custom_custom_examples_how_to_work_with_voc',0.85,NULL);
INSERT INTO "words" VALUES(3066,'','karam','дела, поступки','',NULL,'custom_custom_examples_how_to_work_with_voc',0.85,NULL);
INSERT INTO "words" VALUES(3067,'','bhumi','(букв) земля','метафора: низкий',NULL,'custom_custom_examples_how_to_work_with_voc',0.85,NULL);
INSERT INTO "words" VALUES(3068,'','mer','(букв.) горы','метафора: высокий, высший',NULL,'custom_custom_examples_how_to_work_with_voc',0.85,NULL);
INSERT INTO "words" VALUES(3069,'','kaytay','множество (мужской род)','',NULL,'custom_custom_examples_how_to_work_with_voc',0.85,NULL);
INSERT INTO "words" VALUES(3070,'','dhu','(букв.) путеводная звезда','ведение (когда люди хотят, чтобы их вели - они должны ориентироваться на это; звезда что означает фиксированное направление движения)',NULL,'custom_custom_examples_how_to_work_with_voc',0.85,NULL);
INSERT INTO "words" VALUES(3071,'','updes','взгляды, интерпретации, оценки, утверждения','',NULL,'custom_custom_examples_how_to_work_with_voc',0.85,NULL);
INSERT INTO "words" VALUES(3072,'','первое значение','«загадка».','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3073,'','во','первых, нет словаря, в котором слово ਮੁੰਦਾਵਣੀ / Mundavni переводилось бы как «загадка».','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3074,'','в','третьих, здесь на самом деле нет никакой загадки. Первая половина строки говорит, что в тарели лежат три вещи — Thaal Vich Tin Vastu Payeo — а вторая половина той же строки действительно называет все три:','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3075,'','вторая строка','Amrit Nam Thakur Ka Payeo Jis Ka Sabhs Adharo — не добавляет ни третью, ни четвёртую вещь. Она ясно говорит, что Naam является основой всех трёх вещей, названных в первой строке. На это прямо указывает выражение Sabhs Adharo — «основание всего».','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3076,'','а гуру амар дас','Thalley Vich Teiy Vastu Payeo.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3077,'','thaal','букв. тарель','метафорически — вместилище; духовно — ум.',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3078,'','vich','букв. в','духовно — внутри, внутренне усвоить.',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3079,'','tin vastu','три вещи, три элемента.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3080,'','payeo','букв. помещено','духовно — осознано, реализовано.',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3081,'','sat','от санскр. satya','пребывающее в вечном бытии; Творец.',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3082,'','santokh','довольство временным миром.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3083,'','vicharo','букв. размышление, рассуждение','духовно — божественное просветление.',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3084,'','amrit','от *A + Mrit*','то, что за пределами смертности; духовно — духовная жизнь.',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3085,'','naam','добродетели.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3086,'','thakur','Создатель-мастер, Тхакур.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3087,'','nam thakur ka','божественные добродетели Тхакура.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3088,'','jis ka','то, что / чего.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3089,'','sabhs','всё.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3090,'','adharo','основание.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3091,'','ум, внутри которого осознаны три реальности','Творец, довольство временным миром и божественное просветление, — это ум, который получает духовную жизнь через реализацию божественных добродетелей, являющихся основанием всей духовности.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3092,'','jay ko','тот, кто.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3093,'','khavey','букв. ест','духовно — принимает, усваивает.',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3094,'','bhunchey','букв. переваривает','духовно — внутренне впитывает.',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3095,'','tis ka','у того.','',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3096,'','hoey udharo','букв. получает спасение','духовно — достигает духовной цели.',NULL,'custom_mundavni_example',0.85,NULL);
INSERT INTO "words" VALUES(3097,'','eh vast','эта вещь, это Mundavni, эта духовность реализации.','',NULL,'custom_mundavni_example',0.85,NULL);
