INSERT INTO "words" VALUES(3115,'','правители, вселяющие страх, и их подданные','(оба) творения Творца.','',NULL,'custom_номер_1_из_неправильно_приведенных_шабдов_с_разбором',0.85,NULL);
INSERT INTO "words" VALUES(3116,'','и правители','Захватчики, и Управляемые ими - являются творениями Творца. Таким образом, основной вопрос заключается в следующем:','',NULL,'custom_номер_1_из_неправильно_приведенных_шабдов_с_разбором',0.85,NULL);
INSERT INTO "words" VALUES(3117,'','следует ли кому','то претендовать на великие добродетели [наам] (?)','до тех пор наслаждайся эгоистичными потворствами, о разум.',NULL,'custom_номер_1_из_неправильно_приведенных_шабдов_с_разбором',0.85,NULL);
INSERT INTO "words" VALUES(3118,'','правители и управляемые','творения единого Творца. Страх можно устранить из нашего разума, если мы примем одно условие (Стих 1 и первая часть Рахао).','',NULL,'custom_номер_1_из_неправильно_приведенных_шабдов_с_разбором',0.85,NULL);
INSERT INTO "words" VALUES(3119,'','ум','это сущность, которая полностью уполномочена делать это. Только тогда реализуется благодать, говорит Нанак. (Вторая часть стиха Рахао, стихи 8 и 11).','',NULL,'custom_номер_1_из_неправильно_приведенных_шабдов_с_разбором',0.85,NULL);
INSERT INTO "words" VALUES(3120,'','джап бани','ПЕРЕВОД СМЫСЛОВ. ВТОРОЕ ИЗДАНИЕ [2].','',NULL,'ast_example',0.85,NULL);
INSERT INTO "words" VALUES(3121,'','у гурбани есть грамматика','многие знают, что она была обнаружена Professor Sahib Singh ji и дана нам как подарок. Мы используем грамматику, чтобы понимать множественное/единственное число, времена (будущее/настоящее), род (женский/мужской контекст) и т. д.','',NULL,'ast_example',0.85,NULL);
INSERT INTO "words" VALUES(3122,'','я хочу начать с вводной информации','с того, что я называю ошибкой новичка. Когда мы смотрим на Джап Джи, у нас часто уже есть заранее сформированное ощущение, и оно обычно возникает потому, что:','',NULL,'ast_example',0.85,NULL);
