INSERT INTO "words" VALUES(3139,'','это красивое завершение джап бани','в конце концов всё упирается в наши собственные поступки','они определяют наш духовный прогресс и достижение цели, а не то, что “делают другие”.',NULL,'ast_example',0.85,NULL);
