INSERT INTO "words" VALUES(3141,'','например, мы хотим кому','то излишне донести себя, понравиться, но одновременно замечаем что в этих попытках мы теряем связь с собой. Это огромный пласт человеческого мышления. Гурмукх поворачивает лицо к Гуру, и перекраивает свою мысль, например, следующим образом.','',NULL,'ast_example',0.85,NULL);
